struct RequestBuilder {
    url: String,
    method: String,
    headers: Vec<(String, String)>,
}

impl RequestBuilder {
    pub fn new(url: impl Into<String>) -> Self {
        Self { url: url.into(), method: "GET".into(), headers: vec![] }
    }

    pub fn method(mut self, method: impl Into<String>) -> Self {
        self.method = method.into();
        self
    }

    pub fn header(mut self, k: impl Into<String>, v: impl Into<String>) -> Self {
        self.headers.push((k.into(), v.into()));
        self
    }

    pub fn build(self) -> Request {
        Request { url: self.url, method: self.method, headers: self.headers }
    }
}

struct User { name: String, email: String }

impl User {
    pub fn name(&self) -> &str { &self.name }          // borrows
    pub fn set_name(&mut self, name: String) { self.name = name; }  // mutably borrows
    pub fn into_name(self) -> String { self.name }     // consumes
}

let user_id = 42u64;
tokio::spawn(async move {
    fetch_user(user_id).await   // user_id moved into closure; no borrow issue
});
